  async events(me,el){await this._crud(me,el,{table:'events',title:'Events',icon:'fa-calendar-days',fields:[['title','Title'],['event_date','Date & Time','datetime-local'],['location','Location'],['description','Details','textarea']],render:r=>'<b>'+UI.esc(r.title)+'</b><br><span class="muted small">'+UI.date(r.event_date)+' • '+UI.esc(r.location||'')+'</span>'});},
