    (isAdmin?'<div class="card" style="margin-bottom:16px"><h3 style="margin:0 0 10px">Mark Staff Present</h3><div class="grid g3"><input id="ad" type="date" class="input" value="'+today+'"><select id="am" class="input"><option value="">Select staff…</option>'+members.map(m=>'<option value="'+m.id+'">'+UI.esc(m.full_name||m.email)+'</option>').join('')+'</select><button class="btn btn-primary" onclick="Modules._mark()">Mark Present</button></div></div>':'')+
    '<div class="card"><h3 style="margin:0 0 12px"><i class="fas fa-user-check brand-text"></i> Recent Attendance</h3>'+(Object.keys(byDate).length?Object.keys(byDate).sort().reverse().slice(0,14).map(d=>'<div style="padding:8px 0;border-bottom:1px solid var(--border)"><b>'+UI.date(d)+'</b> — '+byDate[d].length+' present</div>').join(''):'<span class="muted small">No records yet.</span>')+'</div>';
