  // ---- Analytics & Charts ----
  async analytics(me,el){
    let fin=[],deals=[],orders=[],inv=[];
    try{fin=(await sb.from('finances').select('*')).data||[];}catch(e){}
    try{deals=(await sb.from('deals').select('*')).data||[];}catch(e){}
    try{orders=(await sb.from('orders').select('*')).data||[];}catch(e){}
    try{inv=(await sb.from('invoices').select('*')).data||[];}catch(e){}
    el.innerHTML='<div class="grid g2"><div class="card"><h3 style="margin:0 0 10px"><i class="fas fa-chart-line brand-text"></i> Income vs Expense</h3><canvas id="cFin" height="180"></canvas></div><div class="card"><h3 style="margin:0 0 10px"><i class="fas fa-chart-pie brand-text"></i> Sales Pipeline</h3><canvas id="cPipe" height="180"></canvas></div></div>'+
    '<div class="card" style="margin-top:16px"><h3 style="margin:0 0 10px"><i class="fas fa-chart-column brand-text"></i> Monthly Income Trend</h3><canvas id="cTrend" height="120"></canvas></div>';
    if(typeof Chart==='undefined'){return;}
    const inc=fin.filter(f=>f.type==='income').reduce((a,b)=>a+Number(b.amount),0);
    const exp=fin.filter(f=>f.type==='expense').reduce((a,b)=>a+Number(b.amount),0);
    try{new Chart(document.getElementById('cFin'),{type:'doughnut',data:{labels:['Income','Expense'],datasets:[{data:[inc,exp],backgroundColor:['#16a34a','#dc2626']}]}});}catch(e){}
    const stages=['new','negotiation','won','lost'];const sc=stages.map(s=>deals.filter(d=>(d.stage||'new')===s).length);
    try{new Chart(document.getElementById('cPipe'),{type:'bar',data:{labels:stages,datasets:[{label:'Deals',data:sc,backgroundColor:(CONFIG.THEME?CONFIG.THEME.primary:'#4f46e5')}]},options:{plugins:{legend:{display:false}}}});}catch(e){}
    const months={};fin.filter(f=>f.type==='income').forEach(f=>{const m=(f.date||'').slice(0,7)||'—';months[m]=(months[m]||0)+Number(f.amount||0);});
    const mk=Object.keys(months).sort();
    try{new Chart(document.getElementById('cTrend'),{type:'line',data:{labels:mk,datasets:[{label:'Income',data:mk.map(k=>months[k]),borderColor:(CONFIG.THEME?CONFIG.THEME.primary:'#4f46e5'),fill:false,tension:.3}]}});}catch(e){}
  },

