    '<div class="card" style="margin-bottom:16px"><h3 style="margin:0 0 10px"><i class="fas fa-user-plus brand-text"></i> Register Patient</h3><div class="grid g4"><input id="ptN" class="input" placeholder="Full name"><input id="ptMRN" class="input" placeholder="MRN (auto if blank)"><input id="ptP" class="input" placeholder="Phone"><select id="ptG" class="input"><option value="">Sex</option><option>Female</option><option>Male</option></select></div><div class="grid g4" style="margin-top:8px"><input id="ptDOB" class="input" type="date" title="Date of birth"><input id="ptB" class="input" placeholder="Blood group"><input id="ptA" class="input" placeholder="Address"><input id="ptAl" class="input" placeholder="Allergies"></div><button class="btn btn-primary" style="margin-top:8px" onclick="Modules._addPatient()">Save Patient</button></div>'+
    '<div class="card"><h3 style="margin:0 0 12px"><i class="fas fa-hospital-user brand-text"></i> Patient Register</h3><div style="overflow-x:auto"><table><thead><tr><th>MRN</th><th>Name</th><th>Sex</th><th>Phone</th><th>Blood</th></tr></thead><tbody id="ptBody"></tbody></table></div></div>';
