  _ptFilter(){var q=((document.getElementById('ptq')||{}).value||'').toLowerCase();var list=(Modules.__patients||[]).filter(function(p){return [p.full_name,p.mrn,p.phone].some(function(v){return (v||'').toLowerCase().includes(q);});});document.getElementById('ptBody').innerHTML=list.length?list.map(function(p){return '<tr><td><b>'+UI.esc(p.mrn||'—')+'</b></td><td>'+UI.esc(p.full_name||'')+'</td><td>'+UI.esc(p.sex||'—')+'</td><td>'+UI.esc(p.phone||'—')+'</td><td>'+UI.esc(p.blood_group||'—')+'</td></tr>';}).join(''):'<tr><td colspan="5" style="text-align:center;color:var(--muted)">No patients yet.</td></tr>';},
  async _addPatient(){var n=document.getElementById('ptN').value.trim();if(!n){UI.toast('Name required','error');return;}var mrn=document.getElementById('ptMRN').value.trim()||('MRN'+Date.now().toString().slice(-6));await sb.from('patients').insert([{full_name:n,mrn:mrn,phone:document.getElementById('ptP').value.trim(),sex:document.getElementById('ptG').value,dob:document.getElementById('ptDOB').value||null,blood_group:document.getElementById('ptB').value.trim(),address:document.getElementById('ptA').value.trim(),allergies:document.getElementById('ptAl').value.trim()}]);Modules._logAudit('Registered patient '+mrn);UI.toast('Patient saved');location.reload();},

