// ---------- OPTIONAL free automation pack (Supabase Edge Functions) ----------
// 100% free (Supabase free tier). NO paid AI API. These are OPTIONAL — the app
// works fully without them; deploy only the ones you want for hands-off alerts.
TPL.edgeFunctions = function (c) {
    const files = {};
    const lowStock = c.features.includes('inventory');
    const contractsOn = c.features.includes('contracts');
    const invoicesOn = c.features.includes('invoices');

    // supabase config.toml
    files['supabase/config.toml'] = `# Supabase project config (free tier). Generated by Clinic Connect / HMG Concepts.\nproject_id = "${(c.shortName || 'business').toLowerCase().replace(/[^a-z0-9]+/g, '-')}"\n\n[functions.daily-digest]\nverify_jwt = false\n${lowStock ? '\n[functions.low-stock-alert]\nverify_jwt = false\n' : ''}${contractsOn || invoicesOn ? '\n[functions.renewal-reminders]\nverify_jwt = false\n' : ''}`;

    // .gitignore so secrets never leak
    files['supabase/.gitignore'] = `# Never commit secrets or local Supabase state\n.env\n.branches\n.temp\n`;

    // shared email helper note (uses Resend free tier — no credit card)
    const emailHelper = `// Free email via Resend (https://resend.com — free tier, no card).\n// Swap for any SMTP/email API if you prefer. NO AI API is used anywhere.\nasync function sendEmail(to, subject, html) {\n  const key = Deno.env.get("RESEND_API_KEY");\n  const from = Deno.env.get("FROM_EMAIL") || "onboarding@resend.dev";\n  if (!key) { console.log("RESEND_API_KEY not set — skipping email"); return; }\n  await fetch("https://api.resend.com/emails", {\n    method: "POST",\n    headers: { "Authorization": "Bearer " + key, "Content-Type": "application/json" },\n    body: JSON.stringify({ from, to: Array.isArray(to) ? to : [to], subject, html })\n  });\n}\n`;

    // 1) Daily digest -> posts a summary to the in-app inbox (and optional email to admins)
    files['supabase/functions/daily-digest/index.ts'] =
`// ============================================================================\n// OPTIONAL Edge Function: daily-digest\n// Posts a daily business summary to the in-app Inbox and (optionally) emails\n// admins. Runs on a free Supabase Cron schedule. NO paid AI API.\n//\n// DEPLOY (see docs/AUTOMATION.md):\n//   supabase functions deploy daily-digest --no-verify-jwt\n//   supabase secrets set RESEND_API_KEY=your_key FROM_EMAIL=you@domain\n//   select cron.schedule('daily-digest','0 7 * * *',\n//     $$ select net.http_post(url:='https://<ref>.functions.supabase.co/daily-digest',\n//        headers:='{"Content-Type":"application/json"}'::jsonb) $$);\n// ============================================================================\nimport { createClient } from "https://esm.sh/@supabase/supabase-js@2";\n${emailHelper}\nDeno.serve(async () => {\n  const url = Deno.env.get("SUPABASE_URL") ?? Deno.env.get("PROJECT_URL");\n  const key = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? Deno.env.get("SERVICE_ROLE_KEY");\n  const admin = createClient(url, key);\n  const today = new Date().toISOString().slice(0,10);\n\n  let income = 0, expense = 0, orders = 0, lowStock = [];\n  try { const { data } = await admin.from("finances").select("type,amount,date").eq("date", today);\n    (data||[]).forEach(r => { if (r.type==="income") income+=Number(r.amount||0); else expense+=Number(r.amount||0); }); } catch(_){}\n  try { const { data } = await admin.from("orders").select("id,created_at"); orders=(data||[]).filter(o=>String(o.created_at||"").slice(0,10)===today).length; } catch(_){}\n  try { const { data } = await admin.from("inventory").select("name,quantity,reorder_level");\n    lowStock=(data||[]).filter(i=>Number(i.quantity||0)<=Number(i.reorder_level||0)).map(i=>i.name); } catch(_){}\n\n  const body = "Daily summary for " + today + ":\\n" +\n    "• Income today: " + income + "\\n• Expense today: " + expense + "\\n• Orders today: " + orders + "\\n" +\n    (lowStock.length ? "• Low stock: " + lowStock.join(", ") : "• Stock levels OK");\n\n  try { await admin.from("messages").insert([{ from_id: null, to_id: null, subject: "📊 Daily Digest — " + today, body }]); } catch(_){}\n\n  try {\n    const { data: admins } = await admin.from("profiles").select("email").eq("role","admin");\n    const emails = (admins||[]).map(a=>a.email).filter(Boolean);\n    if (emails.length) await sendEmail(emails, "Daily Digest — " + today, "<pre>" + body + "</pre>");\n  } catch(_){}\n\n  return new Response(JSON.stringify({ ok:true, income, expense, orders, lowStock }), { headers:{ "Content-Type":"application/json" }});\n});\n`;

    // 2) Low-stock alert
    if (lowStock) {
        files['supabase/functions/low-stock-alert/index.ts'] =
`// ============================================================================\n// OPTIONAL Edge Function: low-stock-alert\n// Emails admins when any product hits/falls below its reorder level, and posts\n// an in-app Inbox notice. Free (Resend free tier). NO paid AI API.\n//\n// DEPLOY:\n//   supabase functions deploy low-stock-alert --no-verify-jwt\n//   supabase secrets set RESEND_API_KEY=your_key FROM_EMAIL=you@domain\n//   select cron.schedule('low-stock-alert','0 8 * * *',\n//     $$ select net.http_post(url:='https://<ref>.functions.supabase.co/low-stock-alert',\n//        headers:='{"Content-Type":"application/json"}'::jsonb) $$);\n// ============================================================================\nimport { createClient } from "https://esm.sh/@supabase/supabase-js@2";\n${emailHelper}\nDeno.serve(async () => {\n  const url = Deno.env.get("SUPABASE_URL") ?? Deno.env.get("PROJECT_URL");\n  const key = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? Deno.env.get("SERVICE_ROLE_KEY");\n  const admin = createClient(url, key);\n  const { data } = await admin.from("inventory").select("name,quantity,reorder_level");\n  const low = (data||[]).filter(i=>Number(i.quantity||0)<=Number(i.reorder_level||0));\n  if (!low.length) return new Response(JSON.stringify({ ok:true, low:0 }), { headers:{ "Content-Type":"application/json" }});\n  const list = low.map(i=>i.name + " (" + i.quantity + ")").join(", ");\n  try { await admin.from("messages").insert([{ from_id:null, to_id:null, subject:"⚠️ Low stock alert", body:"Reorder needed: " + list }]); } catch(_){}\n  try {\n    const { data: admins } = await admin.from("profiles").select("email").eq("role","admin");\n    const emails=(admins||[]).map(a=>a.email).filter(Boolean);\n    if (emails.length) await sendEmail(emails, "Low stock alert", "<p>Reorder needed:</p><p>" + list + "</p>");\n  } catch(_){}\n  return new Response(JSON.stringify({ ok:true, low:low.length }), { headers:{ "Content-Type":"application/json" }});\n});\n`;
    }

    // 3) Renewal / due reminders (contracts &/or invoices)
    if (contractsOn || invoicesOn) {
        files['supabase/functions/renewal-reminders/index.ts'] =
`// ============================================================================\n// OPTIONAL Edge Function: renewal-reminders\n// Flags ${contractsOn ? 'contracts expiring within 14 days' : ''}${contractsOn && invoicesOn ? ' and ' : ''}${invoicesOn ? 'unpaid invoices' : ''} —\n// posts an in-app Inbox notice and emails admins. Free. NO paid AI API.\n//\n// DEPLOY:\n//   supabase functions deploy renewal-reminders --no-verify-jwt\n//   supabase secrets set RESEND_API_KEY=your_key FROM_EMAIL=you@domain\n//   select cron.schedule('renewal-reminders','0 9 * * 1',\n//     $$ select net.http_post(url:='https://<ref>.functions.supabase.co/renewal-reminders',\n//        headers:='{"Content-Type":"application/json"}'::jsonb) $$);\n// ============================================================================\nimport { createClient } from "https://esm.sh/@supabase/supabase-js@2";\n${emailHelper}\nDeno.serve(async () => {\n  const url = Deno.env.get("SUPABASE_URL") ?? Deno.env.get("PROJECT_URL");\n  const key = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? Deno.env.get("SERVICE_ROLE_KEY");\n  const admin = createClient(url, key);\n  const lines = [];\n  const soon = new Date(Date.now() + 14*864e5).toISOString().slice(0,10);\n  ${contractsOn ? `try { const { data } = await admin.from("contracts").select("title,end_date,party");\n    (data||[]).filter(x=>x.end_date && x.end_date <= soon).forEach(x=>lines.push("Contract due: " + x.title + " (" + x.party + ") — " + x.end_date)); } catch(_){}` : ''}\n  ${invoicesOn ? `try { const { data } = await admin.from("invoices").select("number,customer,amount,paid");\n    (data||[]).filter(x=>Number(x.amount||0) > Number(x.paid||0)).forEach(x=>lines.push("Unpaid invoice: " + x.number + " (" + x.customer + ") — balance " + (Number(x.amount||0)-Number(x.paid||0)))); } catch(_){}` : ''}\n  if (!lines.length) return new Response(JSON.stringify({ ok:true, items:0 }), { headers:{ "Content-Type":"application/json" }});\n  const body = lines.join("\\n");\n  try { await admin.from("messages").insert([{ from_id:null, to_id:null, subject:"🔔 Reminders", body }]); } catch(_){}\n  try { const { data: admins } = await admin.from("profiles").select("email").eq("role","admin");\n    const emails=(admins||[]).map(a=>a.email).filter(Boolean);\n    if (emails.length) await sendEmail(emails, "Business reminders", "<pre>" + body + "</pre>"); } catch(_){}\n  return new Response(JSON.stringify({ ok:true, items:lines.length }), { headers:{ "Content-Type":"application/json" }});\n});\n`;
    }

    // Automation docs
    files['docs/AUTOMATION.md'] =
`# Free Automation Pack (OPTIONAL) — Clinic Connect\n\nThese **Supabase Edge Functions** add hands-off alerts. They are **100% free**\n(Supabase free tier + Resend free email tier) and use **NO paid AI API**.\nEverything works without them — deploy only what you want.\n\n## What's included\n- **daily-digest** — posts a daily summary (income, expense, orders${lowStock ? ', low stock' : ''}) to the in-app Inbox${'`'}messages${'`'} table and emails admins.\n${lowStock ? '- **low-stock-alert** — emails admins + posts an Inbox notice when products hit their reorder level.\\n' : ''}${contractsOn || invoicesOn ? '- **renewal-reminders** — flags ' + (contractsOn ? 'expiring contracts' : '') + (contractsOn && invoicesOn ? ' and ' : '') + (invoicesOn ? 'unpaid invoices' : '') + '.\\n' : ''}\n## One-time setup\n1. Install the free Supabase CLI: https://supabase.com/docs/guides/cli\n2. ${'`'}supabase login${'`'} then ${'`'}supabase link --project-ref <your-ref>${'`'}\n3. (For emails) create a free Resend account, verify a sender, copy the API key.\n\n## Deploy a function (example: daily-digest)\n${'```'}\nsupabase functions deploy daily-digest --no-verify-jwt\nsupabase secrets set RESEND_API_KEY=your_resend_key FROM_EMAIL=you@yourdomain\n${'```'}\nThe function automatically receives ${'`'}SUPABASE_URL${'`'} and ${'`'}SUPABASE_SERVICE_ROLE_KEY${'`'}\nfrom Supabase — you never put the service_role key in your website code.\n\n## Schedule it (free Supabase Cron)\nEnable the ${'`'}pg_cron${'`'} and ${'`'}pg_net${'`'} extensions (Database → Extensions), then run\nin the SQL Editor (replace <ref>):\n${'```'}sql\nselect cron.schedule('daily-digest','0 7 * * *',\n  $$ select net.http_post(\n       url:='https://<ref>.functions.supabase.co/daily-digest',\n       headers:='{"Content-Type":"application/json"}'::jsonb) $$);\n${'```'}\n\n## 🔒 Security\n- The **service_role** key lives ONLY in the Supabase secrets vault — never in\n  GitHub, never in ${'`'}config.js${'`'}, never in the browser.\n- Functions are scheduled server-side; no user can trigger them with elevated rights.\n\n---\nNeed help wiring this up? ${HMG.name} — ${HMG.whatsapp}\n`;

    return files;
};

function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
window.TPL = TPL;
